#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 2e5 + 5;
ll a[MAXN], f[MAXN][25], t, d, n, m;
ll h(ll x, ll y)
{
	return max(f[y][((ll)(log2(y - x + 1)))], f[x + (1 << ((ll)(log2(y - x + 1)))) - 1][((ll)(log2(y - x + 1)))]);
}
int main(void)
{
	cin >> m >> d;
	for (int i = 1; i <= m; ++i)
	{
		char c;
		ll x;
		cin >> c >> x;
		if (c == 'A')
		{
			a[++n] = (x + t) % d;
			f[n][0] = a[n];
			for (int i = 1; n - (1 << i) >= 0; ++i)
			{
				f[n][i] = max(f[n][i - 1], f[n - (1 << (i - 1))][i - 1]);
			}
		}
		else
		{
			int ans;
			if (ans == 1)
			{
				cout << a[n] << '\n';
				t = a[n];
			}
			else
			{
				ans = h(n - x + 1, n);
				cout << ans << '\n';
				t = ans;
			}
		}
	}
	return false;
}
